import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { Interest, Legislator, Sponsorship, Vote } from '../../core/models';
import { AuthService } from '../../core/services/auth.service';

@Component({
  selector: 'app-legislator-detail',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './legislator-detail.component.html',
  styleUrl: './legislator-detail.component.css',
})
export class LegislatorDetailComponent implements OnInit {
  private auth = inject(AuthService);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly isEditor = this.auth.isEditor;

  legislatorId = signal('');
  modal = signal('');
  loading = signal(false);
  error = signal('');

  // Mock data — mockup_cleaner clears these; service_agent wires getLegislator().
  legislators = signal<Legislator[]>([
    { id: 'l1', name: 'Sen. Marcia Holloway', chamber: 'senate', district: 'S-12', party: 'Republican' },
  ]);

  sponsorships = signal<Sponsorship[]>([
    {
      id: 's1',
      billId: 'b1',
      legislatorId: 'l1',
      isPrimary: true,
      bill: { id: 'b1', number: 'HB0042', title: 'Renewable Energy Tax Incentives', summary: '', status: 'committee', session: 2025, sectors: ['energy', 'environment'] },
    },
    {
      id: 's4',
      billId: 'b4',
      legislatorId: 'l1',
      isPrimary: false,
      bill: { id: 'b4', number: 'SB0075', title: 'Grid Resilience & Storage Standards', summary: '', status: 'signed', session: 2024, sectors: ['energy'] },
    },
  ]);

  votes = signal<Vote[]>([
    { id: 'v1', billId: 'b1', legislatorId: 'l1', choice: 'yea' },
    { id: 'v10', billId: 'b4', legislatorId: 'l1', choice: 'yea' },
    { id: 'v11', billId: 'b2', legislatorId: 'l1', choice: 'nay' },
  ]);

  interests = signal<Interest[]>([
    { id: 'i1', legislatorId: 'l1', entity: 'Wasatch Solar Holdings', sector: 'energy' },
    { id: 'i2', legislatorId: 'l1', entity: 'Holloway Family Trust', sector: 'real-estate' },
  ]);

  // Bill numbers referenced by votes, for display without a join.
  billIndex = signal<Record<string, string>>({
    b1: 'HB0042', b2: 'SB0110', b4: 'SB0075',
  });

  readonly legislator = computed<Legislator | undefined>(() => {
    const id = this.legislatorId();
    const list = this.legislators();
    return list.find((l) => l.id === id) ?? list[0];
  });

  ngOnInit(): void {
    this.legislatorId.set(this.route.snapshot.paramMap.get('id') ?? '');
    this.modal.set(this.route.snapshot.queryParamMap.get('modal') ?? '');
  }

  billNumber(billId: string): string {
    return this.billIndex()[billId] ?? billId;
  }

  openModal(name: string): void {
    this.modal.set(name);
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: name },
      queryParamsHandling: 'merge',
    });
  }

  closeModal(): void {
    this.modal.set('');
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: null },
      queryParamsHandling: 'merge',
    });
  }
}
